package main

import (
	"bytes"
	"fmt"
	"io"
	"os"
	"os/exec"
	"strings"
)

// QuerySLBAndExport executes the aliyun slb DescribeLoadBalancers command
// and pipes the output through jq to filter the LoadBalancers array,
// then saves the result to the specified outputFile.
// It returns the combined stdout/stderr of the final command and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Build the first command: aliyun slb DescribeLoadBalancers --LoadBalancerName NAME
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Build the second command: jq '.LoadBalancers.LoadBalancer[]'
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe between aliyunCmd and jqCmd
	// We get the stdin writer for jqCmd and the stdout reader for aliyunCmd
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe for aliyun stdout: %w", err)
	}

	jqStdin, err := jqCmd.StdinPipe()
	if err != nil {
		aliyunStdout.Close()
		return "", fmt.Errorf("failed to get jq stdin pipe: %w", err)
	}

	// Capture stderr from jq for debugging
	var jqStderr bytes.Buffer
	jqCmd.Stderr = &jqStderr

	// Capture final output (stdout of jq)
	var finalOutput bytes.Buffer
	jqCmd.Stdout = &finalOutput

	// Start the first command
	if err := aliyunCmd.Start(); err != nil {
		aliyunStdout.Close()
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Connect aliyun's stdout to jq's stdin
	go func() {
		defer jqStdin.Close()
		_, _ = io.Copy(jqStdin, aliyunStdout)
	}()

	// Start the second command
	if err := jqCmd.Start(); err != nil {
		aliyunCmd.Wait() // ensure aliyunCmd finishes
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for aliyun command to finish
	if err := aliyunCmd.Wait(); err != nil {
		jqStdin.Close() // signal end of input to jq
		jqCmd.Wait()    // wait for jq to finish reading
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Close the stdin of jq to signal EOF so it can finish
	jqStdin.Close()

	// Wait for jq command to finish
	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %s; error: %w", jqStderr.String(), err)
	}

	// Write the output to the specified file
	if err := os.WriteFile(outputFile, finalOutput.Bytes(), 0644); err != nil {
		return "", fmt.Errorf("failed to write output to file %s: %w", outputFile, err)
	}

	return finalOutput.String(), nil
}

func main() {
	// Example usage
	if len(os.Args) < 3 {
		fmt.Println("Usage: go run main.go <LoadBalancerName> <OutputFile>")
		os.Exit(1)
	}

	name := os.Args[1]
	outFile := os.Args[2]

	result, err := QuerySLBAndExport(name, outFile)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Println("Exported SLB info to", outFile)
	fmt.Println("Output preview:")
	fmt.Println(strings.TrimSpace(result))
}

