	safeOutput = strings.ReplaceAll(safeOutput, ";", "")
	safeOutput = strings.ReplaceAll(safeOutput, "|", "")
	safeOutput = strings.ReplaceAll(safeOutput, "&", "")
	safeOutput = strings.ReplaceAll(safeOutput, "`", "")

	// Build the first command: aliyun slb DescribeLoadBalancers --LoadBalancerName NAME
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", safeName)

	// Build the second command: jq '.LoadBalancers.LoadBalancer[]'
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe between aliyunCmd and jqCmd
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
