	}

	jqStdin, err := jqCmd.StdinPipe()
	if err != nil {
		aliyunStdout.Close()
		return "", fmt.Errorf("failed to get jq stdin pipe: %w", err)
	}

	// Capture stderr from jq for debugging
	var jqStderr bytes.Buffer
	jqCmd.Stderr = &jqStderr

	// Capture final output (stdout of jq)
	var finalOutput bytes.Buffer
	jqCmd.Stdout = &finalOutput

	// Start the first command
	if err := aliyunCmd.Start(); err != nil {
		aliyunStdout.Close()
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Connect aliyun's stdout to jq's stdin
	go func() {
		defer jqStdin.Close()
		_, _ = io.Copy(jqStdin, aliyunStdout)
	}()

	// Start the second command
	if err := jqCmd.Start(); err != nil {
		aliyunCmd.Wait()
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for aliyun command to finish
	if err := aliyunCmd.Wait(); err != nil {
		jqStdin.Close()
		jqCmd.Wait()
		return "", fmt.Errorf("aliyun command failed: %w", err)
