		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start jq
	if err := jqCmd.Start(); err != nil {
		aliyunCmd.Wait() //nolint:errcheck
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for aliyun to finish
	if err := aliyunCmd.Wait(); err != nil {
		jqCmd.Wait() //nolint:errcheck
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Wait for jq to finish
	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	// Return success message or empty string as per requirement
	return fmt.Sprintf("SLB information exported to %s successfully", outputFile), nil
}

