// QuerySLBAndExport executes the aliyun slb DescribeLoadBalancers command
// and pipes the output through jq to filter the LoadBalancers array.
// The result is saved to the specified outputFile.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
