	safeName = strings.ReplaceAll(safeName, "&", "")
	safeName = strings.ReplaceAll(safeName, "$", "")
	safeName = strings.TrimSpace(safeName)

	// Build the aliyun CLI command using safer approach with arguments
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", safeName)

	// Start the jq command
	cmdJq := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe between aliyun and jq
	aliyunStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe for aliyun stdout: %w", err)
	}

	cmdJq.Stdin = aliyunStdout

	// Capture jq output
	var jqOutput bytes.Buffer
	cmdJq.Stdout = &jqOutput

	// Start both commands
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	if err := cmdJq.Start(); err != nil {
		aliyunCmd.Wait()
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for aliyun to finish and close its stdout
	if err := aliyunCmd.Wait(); err != nil {
		cmdJq.Wait()
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	aliyunStdout.Close()

	// Wait for jq to finish
	if err := cmdJq.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	// Write output to file
	err = os.WriteFile(outputFile, jqOutput.Bytes(), 0644)
	if err != nil {
