	jqCmd.Stdout = outFile
	jqCmd.Stderr = os.Stderr

	// Connect the commands
	aliyunCmdStdout, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %w", err)
	}
	aliyunCmd.Stderr = os.Stderr

	jqCmd.Stdin = aliyunCmdStdout

	// Start both commands
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	if err := jqCmd.Start(); err != nil {
		aliyunCmd.Wait()
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for aliyun to finish and close its stdout
	aliyunCmd.Wait()
	aliyunCmdStdout.Close()

	// Wait for jq to finish
	jqErr := jqCmd.Wait()

	// Capture any output from aliyun before failure
	var aliyunOutput bytes.Buffer
	aliyunOutput.ReadFrom(aliyunCmdStdout)

	if jqErr != nil {
		return "", fmt.Errorf("jq processing failed: %w", jqErr)
	}

	return fmt.Sprintf("Successfully exported SLB data to %s", outputFile), nil
}

