package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate inputs to prevent command injection
	if strings.ContainsAny(loadBalancerName, "\"`$\n\r\t|&;<>(){}[]") || strings.ContainsAny(outputFile, "\"`$\n\r\t|&;<>(){}[]") {
		return "", fmt.Errorf("invalid characters in input parameters")
	}

	// Validate that outputFile doesn't contain path traversal or absolute paths (optional security measure)
	// For simplicity, we'll just check for common path separators
	if strings.Contains(outputFile, "../") || strings.Contains(outputFile, "./") || strings.HasPrefix(outputFile, "/") {
		return "", fmt.Errorf("invalid output file path")
	}

	// Define the commands
	aliyunCmd := "aliyun"
	aliyunArgs := []string{"slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName}

	jqCmd := "jq"
	jqArgs := []string{".LoadBalancers.LoadBalancer[]"}

	// Create the aliyun command
	aliyunProc := exec.Command(aliyunCmd, aliyunArgs...)

	// Create the jq command
	jqProc := exec.Command(jqCmd, jqArgs...)

	// Create a pipe from aliyun to jq
	aliyunStdout, err := aliyunProc.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe for aliyun command: %w", err)
	}

	jqProc.Stdin = aliyunStdout

	// Capture jq output
	var jqOutput bytes.Buffer
	jqProc.Stdout = &jqOutput

	// Capture stderr from both commands
	var aliyunStderr, jqStderr bytes.Buffer
	aliyunProc.Stderr = &aliyunStderr
	jqProc.Stderr = &jqStderr

	// Start the jq command first so it's ready to read
	if err := jqProc.Start(); err != nil {
		aliyunStdout.Close()
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Start the aliyun command
	if err := aliyunProc.Start(); err != nil {
		jqProc.Process.Kill()
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Close the stdout pipe so jq knows when aliyun is done
	aliyunStdout.Close()

	// Wait for both commands to complete
	aliyunErr := aliyunProc.Wait()
	jqErr := jqProc.Wait()

	// Combine errors
	var combinedError error
	if aliyunErr != nil {
		combinedError = fmt.Errorf("aliyun command failed: %w, stderr: %s", aliyunErr, aliyunStderr.String())
	}
	if jqErr != nil {
		if combinedError != nil {
			combinedError = fmt.Errorf("%v; jq command failed: %w, stderr: %s", combinedError, jqErr, jqStderr.String())
		} else {
			combinedError = fmt.Errorf("jq command failed: %w, stderr: %s", jqErr, jqStderr.String())
		}
	}

	// Write output to file if no errors
	if combinedError == nil {
		err := os.WriteFile(outputFile, jqOutput.Bytes(), 0644)
		if err != nil {
			return "", fmt.Errorf("failed to write output to file: %w", err)
		}
	}

	return jqOutput.String(), combinedError
}

