	if err := aliyunCmd.Wait(); err != nil {
		jqStdin.Close() // signal end of input to jq
		jqCmd.Wait()    // wait for jq to finish reading
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Close the stdin of jq to signal EOF so it can finish
	jqStdin.Close()

	// Wait for jq command to finish
	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %s; error: %w", jqStderr.String(), err)
